import React, { useState, useEffect, useRef } from "react";
import {
  Bar, Line, Legend, Cell, LabelList, XAxis, YAxis, CartesianGrid, Tooltip,
  ResponsiveContainer, ComposedChart, BarChart,
} from "recharts";

/* ============================================================
   LubLub — Simulador de Precificação de Lubrificantes
   Meta: maior MARGEM ABSOLUTA acumulada, equilibrando margem
   unitária x volume. Elasticidade oculta por produto.
   Preços de referência baseados no mercado brasileiro (2025-26).
   ============================================================ */

const C = {
  bg: "#1a222e", panel: "#232d3a", panel2: "#2d3846", border: "#3f4c5e",
  text: "#eef4fb", muted: "#a3b4c8", faint: "#71829a",
  blue: "#3d97f2", oil: "#f2a51c", oilDim: "#6e4c11",
  green: "#3ddc8a", greenDim: "#1f6b45", red: "#f2555a", steel: "#a6b8cc",
};

const PRODUCT_IMG = {
  m2050: "data:image/webp;base64,",
  m1030: "data:image/webp;base64,",
  c530: "data:image/webp;base64,",
  c2050: "data:image/webp;base64,",
  truck: "data:image/webp;base64,",
};
const LOGO_IMG = "data:image/webp;base64,";const money = (v) => new Intl.NumberFormat("pt-BR", { style: "currency", currency: "BRL", maximumFractionDigits: 0 }).format(Math.round(v));
const money2 = (v) => new Intl.NumberFormat("pt-BR", { style: "currency", currency: "BRL", maximumFractionDigits: 2 }).format(v);

// --- PDF mínimo (sem dependências) para baixar a melhor rodada ---
function latin1(str) { const a = new Uint8Array(str.length); for (let i = 0; i < str.length; i++) { const c = str.charCodeAt(i); a[i] = c < 256 ? c : 63; } return a; }
function buildPDF(lines) {
  const esc = (s) => String(s).replace(/\\/g, "\\\\").replace(/\(/g, "\\(").replace(/\)/g, "\\)");
  let y = 800; let cs = "";
  for (const ln of lines) {
    y -= (ln.gap != null ? ln.gap : 6) + (ln.s || 10);
    if (ln.t) {
      const font = ln.b ? "F2" : "F1";
      const x = ln.x != null ? ln.x : 56;
      cs += `BT /${font} ${ln.s || 10} Tf ${x} ${y.toFixed(1)} Td (${esc(ln.t)}) Tj ET\n`;
    }
  }
  const objs = [];
  objs[1] = "<< /Type /Catalog /Pages 2 0 R >>";
  objs[2] = "<< /Type /Pages /Kids [3 0 R] /Count 1 >>";
  objs[3] = "<< /Type /Page /Parent 2 0 R /MediaBox [0 0 595 842] /Resources << /Font << /F1 5 0 R /F2 6 0 R >> >> /Contents 4 0 R >>";
  objs[4] = `<< /Length ${latin1(cs).length} >>\nstream\n${cs}\nendstream`;
  objs[5] = "<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica /Encoding /WinAnsiEncoding >>";
  objs[6] = "<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica-Bold /Encoding /WinAnsiEncoding >>";
  let out = "%PDF-1.4\n"; const offsets = [];
  for (let i = 1; i <= 6; i++) { offsets[i] = out.length; out += `${i} 0 obj\n${objs[i]}\nendobj\n`; }
  const xref = out.length;
  out += "xref\n0 7\n0000000000 65535 f \n";
  for (let i = 1; i <= 6; i++) out += String(offsets[i]).padStart(10, "0") + " 00000 n \n";
  out += `trailer\n<< /Size 7 /Root 1 0 R >>\nstartxref\n${xref}\n%%EOF`;
  return latin1(out);
}
function downloadBestRoundPDF({ round, margin, par, mode, items }) {
  const eff = par > 0 ? Math.round((margin / par) * 100) : 0;
  const date = new Date().toLocaleDateString("pt-BR");
  const lines = [
    { t: "LubLub", s: 26, b: true, gap: 4 },
    { t: "Simulador de Precificação de Lubrificantes", s: 11, gap: 2 },
    { t: "Relatório da melhor rodada", s: 13, b: true, gap: 14 },
    { t: `Modo: ${mode === "lab" ? "Laboratório" : "Mercado"}      Emitido em ${date}`, s: 10, gap: 10 },
    { t: `Rodada ${round}`, s: 20, b: true, gap: 16 },
    { t: `Margem da rodada: ${money(margin)}`, s: 15, b: true, gap: 12 },
    { t: `Potencial da rodada: ${money(par)}  (${eff}% aproveitado)`, s: 11, gap: 6 },
    { t: "Detalhe por produto:", s: 12, b: true, gap: 16 },
    ...items.map((it) => ({ t: `- ${it.name}:  preço ${money2(it.price)}  |  ${it.vol} un  |  margem ${money(it.margin)}`, s: 10, gap: 5 })),
    { t: "Gerado pelo Simulador de Precificação LubLub", s: 9, gap: 26 },
  ];
  const blob = new Blob([buildPDF(lines)], { type: "application/pdf" });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url; a.download = `LubLub-melhor-rodada-R${round}.pdf`;
  document.body.appendChild(a); a.click(); a.remove();
  setTimeout(() => URL.revokeObjectURL(url), 3000);
}

const refPrice = (p) => p.competitor + p.advantage;
const demandAt = (price, p, shock = 1) => (p.qmax / (1 + Math.exp(p.k * (price - refPrice(p))))) * shock;
const totalMarginAt = (price, p, shock = 1) => (price - p.cost) * demandAt(price, p, shock);
function optimalOf(p, shock = 1) {
  let bp = p.cost, bm = -1e12, step = p.pack === "balde" ? 1 : 0.5;
  for (let price = p.cost; price <= p.max; price += step) {
    const m = totalMarginAt(price, p, shock);
    if (m > bm) { bm = m; bp = price; }
  }
  return { price: bp, margin: bm };
}

// Identidade fixa dos produtos (o que eles são). A elasticidade vem da FASE.
const BASE_PRODUCTS = [
  { id: "m2050", veh: "moto", name: "LubLub 4T 20W-50", grade: "20W-50", tag: "MOTO 4T · JASO MA2", unit: "1 L", pack: "garrafa",
    body: "#c2410c", cap: "#1c1917", accent: "#f97316", cost: 21, competitor: 33, max: 90,
    nature: "Óleo mineral para moto 4T. Público pulverizado, muitas trocas por ano." },
  { id: "m1030", veh: "moto", name: "LubLub 4T 10W-30", grade: "10W-30", tag: "MOTO 4T · SEMISSINT.", unit: "1 L", pack: "garrafa",
    body: "#b91c1c", cap: "#1c1917", accent: "#ef4444", cost: 28, competitor: 45, max: 110,
    nature: "Semissintético para motos mais novas; segue a recomendação de manual." },
  { id: "c530", veh: "car", name: "LubLub Carros 5W-30 Dexos 1", grade: "5W-30", tag: "CARRO · DEXOS 1 · SINT.", unit: "1 L", pack: "garrafa",
    body: "#1d4ed8", cap: "#0b1220", accent: "#3b82f6", cost: 38, competitor: 60, max: 130,
    nature: "Sintético premium travado por especificação (Dexos 1). Maior ticket da linha leve." },
  { id: "c2050", veh: "car", name: "LubLub Carros 20W-50", grade: "20W-50", tag: "CARRO · MINERAL · SL", unit: "1 L", pack: "garrafa",
    body: "#15803d", cap: "#0b1a10", accent: "#22c55e", cost: 21, competitor: 34, max: 80,
    nature: "Mineral para carros antigos; categoria de grande volume." },
  { id: "truck", veh: "truck", name: "LubLub Truck 15W-40 CI-4", grade: "15W-40", tag: "DIESEL · CI-4 · BALDE", unit: "balde 20 L", pack: "balde",
    body: "#a16207", cap: "#111827", accent: "#eab308", cost: 360, competitor: 460, max: 900,
    nature: "Diesel pesado CI-4 em balde de 20 L, vendido para frotas (B2B). Ticket alto." },
];

// Cada FASE muda as elasticidades (k), a vantagem de marca (advantage) e o tamanho do mercado (qmax),
// gerando ótimos e conclusões diferentes. Calibradas para "copiar o concorrente" render ~60-69%.
const PHASES = [
  { title: "Mercado padrão",
    teaser: "Um mês típico no mercado de lubrificantes: alguns óleos têm clientes fiéis, outros vivem em guerra de preço. Cabe a você descobrir quem é quem.",
    scenario: "Motos e o sintético 5W-30 têm clientes fiéis (preço sobe); o 20W-50 de carro e o diesel de frota disputam no preço (desconte).",
    params: {
      m2050: { k: 0.055, advantage: 16, qmax: 190 }, m1030: { k: 0.05, advantage: 20, qmax: 160 },
      c530: { k: 0.045, advantage: 26, qmax: 175 }, c2050: { k: 0.32, advantage: -3, qmax: 150 },
      truck: { k: 0.025, advantage: -55, qmax: 95 } } },
  { title: "Guerra dos sintéticos",
    teaser: "Importados baratos entraram no mercado e mexeram na lealdade de algumas categorias — as curvas que você conhecia mudaram de lugar. Redescubra cada uma.",
    scenario: "Importados baratos derrubam a lealdade no 5W-30 e no 10W-30 (agora elásticos); falta de mineral e contratos de frota deixam 20W-50 e diesel pouco sensíveis a preço (prêmio).",
    params: {
      m2050: { k: 0.05, advantage: 20, qmax: 180 }, m1030: { k: 0.30, advantage: -4, qmax: 150 },
      c530: { k: 0.28, advantage: -7, qmax: 150 }, c2050: { k: 0.05, advantage: 16, qmax: 150 },
      truck: { k: 0.02, advantage: 150, qmax: 60 } } },
  { title: "Boom de frota",
    teaser: "A safra aqueceu a demanda pesada e novas marcas chegaram nas linhas leves. As sensibilidades mudaram de novo — teste antes de apostar alto.",
    scenario: "Explosão do diesel e do 5W-30 premium (pouco sensíveis — cobre mais); importados de moto acirram a briga no óleo de moto e no 20W-50 (desconte para vender).",
    params: {
      m2050: { k: 0.30, advantage: -4, qmax: 160 }, m1030: { k: 0.28, advantage: -3, qmax: 160 },
      c530: { k: 0.045, advantage: 28, qmax: 185 }, c2050: { k: 0.32, advantage: -4, qmax: 150 },
      truck: { k: 0.02, advantage: 175, qmax: 62 } } },
];
function buildProducts(i) {
  const ph = PHASES[i % PHASES.length];
  return BASE_PRODUCTS.map((b) => {
    const step = b.pack === "balde" ? 1 : 0.5;
    const start = Math.round((b.competitor * 0.9) / step) * step; // chute inicial ingênuo: -10% do concorrente
    return { ...b, ...ph.params[b.id], price: start, history: [] };
  });
}
const elasticityAt = (price, p) => { const x = p.k * (price - refPrice(p)); return (p.k * price) / (1 + Math.exp(-x)); };
function lessonFor(p) {
  const d = optimalOf(p).price / p.competitor - 1;
  const pct = Math.round(Math.abs(d) * 100);
  if (d >= 0.30) return `Muito inelástico nesta fase: clientes fiéis quase não reagem a preço. O ótimo fica ~${pct}% ACIMA do concorrente — cobrar igual a ele deixa muito lucro na mesa.`;
  if (d >= 0.10) return `Inelasticidade moderada nesta fase: dá pra praticar um prêmio de ~${pct}% sobre o concorrente antes de o volume começar a doer. O jogo pende pra margem.`;
  if (d > -0.05) return "Commodity nesta fase: o comprador compara centavo a centavo. Acompanhe o concorrente de perto — subir muito derruba o volume, descontar muito só corrói a margem.";
  if (d > -0.15) return `Sensível a preço nesta fase: um desconto leve (~${pct}% abaixo do concorrente) puxa volume suficiente pra compensar a margem menor por unidade.`;
  return `Muito elástico nesta fase: o ótimo fica ~${pct}% ABAIXO do concorrente. Desconto agressivo multiplica o volume — e com margem unitária gorda, a margem absoluta dispara.`;
}

const EVENTS = {
  1: { mult: 1.0, msg: "📦 Mês comum no centro de distribuição. Hora de definir os preços." },
  2: { mult: 1.2, msg: "🏍️ Temporada de motos — revendas pedem mais óleo de moto (+20%)." },
  3: { mult: 0.9, msg: "🌧️ Chuva forte reduz a rodagem — trocas adiadas (-10%)." },
  4: { mult: 1.0, comp: { id: "c530", to: 66 }, msg: "🛢️ Alta do óleo base: concorrente do 5W-30 subiu para R$66." },
  5: { mult: 1.25, msg: "🚚 Safra escoando — frotas comprando diesel sem parar (+25%)." },
  6: { mult: 1.0, comp: { id: "c2050", to: 30 }, msg: "⚔️ Atacadista rival detonou o preço do 20W-50 para R$30." },
  7: { mult: 0.85, msg: "📉 Economia fraca — revendas seguram estoque (-15%)." },
  8: { mult: 1.15, msg: "🏁 Fechamento de mês — meta das revendas puxa os pedidos (+15%)." },
};
const TOTAL_ROUNDS = 8;

export default function App() {
  const [phase, setPhase] = useState("intro");
  const [round, setRound] = useState(1);
  const [products, setProducts] = useState(() => buildProducts(0));
  const [shock, setShock] = useState(1);
  const [eventMsg, setEventMsg] = useState(EVENTS[1].msg);
  const [totalMargin, setTotalMargin] = useState(0);
  const [parTotal, setParTotal] = useState(0);
  const [lastResults, setLastResults] = useState(null);
  const [roundLog, setRoundLog] = useState([]);
  const [ui, setUi] = useState({});
  const [fx, setFx] = useState([]);
  const [mode, setMode] = useState("market");
  const [earlyWin, setEarlyWin] = useState(false);
  const [selling, setSelling] = useState(null); // fase destino enquanto o popup roda
  const [prepMode, setPrepMode] = useState(null); // modo escolhido enquanto o popup de dicas roda
  const [phaseIdx, setPhaseIdx] = useState(0);
  const totalRounds = mode === "lab" ? 6 : TOTAL_ROUNDS;

  const [displayCash, setDisplayCash] = useState(0);
  const rafRef = useRef();
  useEffect(() => {
    cancelAnimationFrame(rafRef.current);
    const from = displayCash, to = totalMargin, t0 = performance.now(), dur = 900;
    const tick = (t) => {
      const k = Math.min(1, (t - t0) / dur);
      setDisplayCash(from + (to - from) * (1 - Math.pow(1 - k, 3)));
      if (k < 1) rafRef.current = requestAnimationFrame(tick);
    };
    rafRef.current = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(rafRef.current);
  }, [totalMargin]); // eslint-disable-line

  function beginRound(r, prods, m) {
    if (m === "lab") {
      setShock(1);
      setEventMsg("🔬 Laboratório — demanda estável e concorrente fixo. Varra os preços à vontade.");
    } else {
      const ev = EVENTS[r];
      if (ev.comp) setProducts(prods.map((p) => (p.id === ev.comp.id ? { ...p, competitor: ev.comp.to } : p)));
      setShock(ev.mult); setEventMsg(ev.msg);
    }
    setRound(r); setPhase("pricing"); setLastResults(null);
  }
  function start(m) {
    setMode(m);
    const fresh = buildProducts(phaseIdx);
    setProducts(fresh); setTotalMargin(0); setParTotal(0); setDisplayCash(0); setRoundLog([]); setEarlyWin(false); setUi({});
    beginRound(1, fresh, m);
  }
  const restart = () => { setPhaseIdx((i) => (i + 1) % PHASES.length); setPhase("intro"); };
  const setPrice = (id, price) => setProducts((ps) => ps.map((p) => (p.id === id ? { ...p, price } : p)));

  function sell() {
    const results = products.map((p) => {
      const vol = Math.max(0, Math.round(demandAt(p.price, p, shock)));
      const m = (p.price - p.cost) * vol;
      const opt = optimalOf(p, shock);
      const prev = p.history[p.history.length - 1] || null;
      return { id: p.id, price: p.price, competitor: p.competitor, vol, margin: m, unit: p.price - p.cost, opt, prev };
    });
    const roundMargin = results.reduce((s, r) => s + r.margin, 0);
    const roundPar = results.reduce((s, r) => s + r.opt.margin, 0);
    setProducts((ps) => ps.map((p) => {
      const r = results.find((x) => x.id === p.id);
      return { ...p, history: [...p.history, { round, price: r.price, competitor: p.competitor, vol: r.vol, margin: r.margin }] };
    }));
    setTotalMargin((t) => t + roundMargin);
    setParTotal((t) => t + roundPar);
    setRoundLog((l) => [...l, { round, margin: roundMargin, par: roundPar }]);
    setLastResults({ results, roundMargin, roundPar });
    const perfect = roundPar > 0 && roundMargin >= roundPar * 0.999;
    setSelling(perfect ? "end" : "result");   // popup aberto; guarda a fase destino
    if (perfect) setEarlyWin(true);
  }
  function finishSelling(dest) {
    setSelling(null);
    setPhase(dest);
    burst();
    try { window.scrollTo({ top: 0, behavior: "smooth" }); } catch (e) { window.scrollTo(0, 0); }
  }
  function burst() {
    const batch = Array.from({ length: 18 }, (_, i) => ({
      id: Date.now() + i, left: 6 + Math.random() * 88, delay: Math.random() * 0.4,
      dur: 0.9 + Math.random() * 0.7, kind: i % 3 === 0 ? "oil" : "coin",
    }));
    setFx(batch); setTimeout(() => setFx([]), 1900);
  }
  const next = () => (round >= totalRounds ? setPhase("end") : beginRound(round + 1, products, mode));

  const ratio = parTotal > 0 ? totalMargin / parTotal : 0;
  const roundEff = lastResults && lastResults.roundPar > 0 ? lastResults.roundMargin / lastResults.roundPar : 0;
  const mood = phase === "result" ? (roundEff >= 0.7 ? "happy" : roundEff >= 0.45 ? "idle" : "sad") : "idle";
  const time = phase === "result" ? "night" : "day";
  const vehicles = phase === "pricing" ? Math.min(5, 2 + ((round - 1) % 3)) : 0;

  return (
    <div style={{ minHeight: "100vh", background: C.bg, color: C.text, fontFamily: "'Trebuchet MS','Segoe UI',system-ui,sans-serif" }}>
      <StyleTag />
      <div style={{ maxWidth: 660, margin: "0 auto", padding: "16px 14px 40px" }}>
        {phase === "intro" && <Intro onStart={(m) => setPrepMode(m)} phaseIdx={phaseIdx} />}
        {phase !== "intro" && phase !== "end" && (
          <>
            <Garage mood={mood} vehicles={vehicles} time={time} sceneKey={`${phase}-${round}`} />
            <TopBar round={round} cash={displayCash} par={parTotal} total={totalRounds} mode={mode} />
            <EventBanner msg={eventMsg} shock={shock} />
            {phase === "result" && <RoundSummary lr={lastResults} onNext={next} last={round >= totalRounds} />}
            {roundLog.length > 0 && <MarginHistory log={roundLog} />}
            <div style={{ display: "grid", gap: 12, marginTop: 12 }}>
              {products.map((p) => {
                const isOpen = ui[p.id]?.open !== undefined ? ui[p.id].open : p.history.length > 0;
                return (
                  <ProductCard key={p.id} p={p} phase={phase}
                    res={lastResults?.results.find((r) => r.id === p.id)}
                    onPrice={(v) => setPrice(p.id, v)}
                    open={isOpen} xMode={ui[p.id]?.xMode || "price"}
                    toggle={() => setUi((o) => ({ ...o, [p.id]: { ...o[p.id], open: !isOpen } }))}
                    setX={(m) => setUi((o) => ({ ...o, [p.id]: { ...o[p.id], xMode: m } }))} />
                );
              })}
            </div>
            {phase === "pricing" && <BigButton onClick={sell} label="LIBERAR OS PEDIDOS · VENDER" hint="Preços definidos? Atenda os clientes do mês." />}
          </>
        )}
        {phase === "end" && <EndScreen total={totalMargin} par={parTotal} ratio={ratio} products={products} log={roundLog} mode={mode} phaseIdx={phaseIdx} earlyWin={earlyWin} finishedRound={round} totalRounds={totalRounds} onRestart={restart} />}
      </div>
      {selling && <SellingPopup onDone={() => finishSelling(selling)} />}
      {prepMode && <PrepPopup modeLabel={prepMode === "lab" ? "🔬 PREPARANDO O LABORATÓRIO" : "🏭 PREPARANDO A DISTRIBUIDORA"}
        onDone={() => { const m = prepMode; setPrepMode(null); start(m); }} />}
      <div style={{ position: "fixed", inset: 0, pointerEvents: "none", overflow: "hidden", zIndex: 50 }}>
        {fx.map((c) => c.kind === "coin" ? (
          <span key={c.id} style={{ position: "absolute", left: c.left + "%", bottom: "16%", fontSize: 24,
            animation: `riseUp ${c.dur}s ${c.delay}s cubic-bezier(.2,.8,.3,1) forwards` }}>🪙</span>
        ) : (
          <span key={c.id} style={{ position: "absolute", left: c.left + "%", bottom: "16%",
            width: 12, height: 16, background: C.oil, borderRadius: "60% 60% 60% 60% / 80% 80% 40% 40%",
            boxShadow: "0 0 6px rgba(242,165,28,.6)",
            animation: `riseUp ${c.dur}s ${c.delay}s cubic-bezier(.2,.8,.3,1) forwards` }} />
        ))}
      </div>
    </div>
  );
}

/* ---------------- Imagem de produto (frasco SVG original) ---------------- */

function BottleTile({ p, w = 40 }) {
  return (
    <div style={{ background: "radial-gradient(circle at 50% 32%, #f6f9fc, #d7dfe8 72%)",
      borderRadius: 10, padding: "5px 7px", display: "grid", placeItems: "center",
      flexShrink: 0, boxShadow: "inset 0 1px 0 rgba(255,255,255,.7), 0 1px 3px rgba(0,0,0,.35)" }}>
      <img src={PRODUCT_IMG[p.id]} alt={p.name}
        style={{ height: Math.round(w * 2.3), width: "auto", maxWidth: "none", objectFit: "contain",
          display: "block", filter: "drop-shadow(0 3px 4px rgba(0,0,0,.28))" }} />
    </div>
  );
}

/* ---------------- Cena do centro de distribuição (animada) ---------------- */

function Worker({ w = 66, mood = "idle" }) {
  const skin = "#e8b48a", overall = "#2b3a4d";
  const mouth = mood === "happy" ? "M23 33 Q30 40 37 33" : mood === "sad" ? "M24 37 Q30 33 36 37" : "M25 34 Q30 37 35 34";
  const up = mood === "happy";
  return (
    <svg viewBox="0 0 60 96" width={w} style={{ display: "block", overflow: "visible" }}>
      <rect x="21" y="72" width="7" height="18" rx="3" fill="#1c2733" />
      <rect x="32" y="72" width="7" height="18" rx="3" fill="#1c2733" />
      <ellipse cx="24" cy="91" rx="6" ry="3" fill="#0d151d" />
      <ellipse cx="36" cy="91" rx="6" ry="3" fill="#0d151d" />
      {up ? (
        <>
          <rect x="7" y="30" width="6" height="19" rx="3" fill={skin} transform="rotate(38 10 48)" />
          <rect x="47" y="30" width="6" height="19" rx="3" fill={skin} transform="rotate(-38 50 48)" />
        </>
      ) : (
        <>
          <rect x="11" y="44" width="6" height="22" rx="3" fill={overall} transform="rotate(-7 14 45)" />
          <rect x="43" y="44" width="6" height="22" rx="3" fill={overall} transform="rotate(7 46 45)" />
          {/* prancheta */}
          <rect x="42" y="58" width="12" height="15" rx="1.5" fill="#f3f5f8" stroke="#c3ccd6" strokeWidth="0.8" transform="rotate(8 48 65)" />
          <rect x="45" y="56" width="6" height="3" rx="1" fill="#8b97a6" transform="rotate(8 48 65)" />
          <line x1="44" y1="63" x2="52" y2="64" stroke="#9aabbf" strokeWidth="1" transform="rotate(8 48 65)" />
          <line x1="44" y1="66" x2="52" y2="67" stroke="#9aabbf" strokeWidth="1" transform="rotate(8 48 65)" />
        </>
      )}
      {/* uniforme */}
      <rect x="14" y="40" width="32" height="34" rx="10" fill={overall} />
      {/* colete refletivo âmbar */}
      <path d="M17 41 h9 v31 h-9 q-3 0 -3 -6 v-19 q0 -6 3 -6 z" fill={C.oil} />
      <path d="M43 41 h-9 v31 h9 q3 0 3 -6 v-19 q0 -6 -3 -6 z" fill={C.oil} />
      <rect x="17" y="52" width="26" height="3" fill="#eef4fb" opacity="0.85" />
      <rect x="17" y="62" width="26" height="3" fill="#eef4fb" opacity="0.85" />
      <rect x="26" y="34" width="8" height="8" rx="3" fill={skin} />
      <circle cx="30" cy="25" r="13" fill={skin} />
      {/* boné da empresa */}
      <path d="M17 21 a13 13 0 0 1 26 0 z" fill={C.blue} />
      <rect x="14" y="20" width="24" height="4" rx="2" fill="#1f5fb0" />
      <rect x="26" y="13" width="8" height="3" rx="1.5" fill={C.oil} />
      <g className="eye"><ellipse cx="25" cy="25" rx="1.9" ry="2.6" fill="#20140c" /><ellipse cx="35" cy="25" rx="1.9" ry="2.6" fill="#20140c" /></g>
      <path d={mouth} fill="none" stroke="#20140c" strokeWidth="1.8" strokeLinecap="round" />
    </svg>
  );
}

function Wheel({ cx, cy, r = 8 }) {
  return (
    <g className="wheel" style={{ transformOrigin: `${cx}px ${cy}px` }}>
      <circle cx={cx} cy={cy} r={r} fill="#232c37" stroke={C.steel} strokeWidth="2" />
      <line x1={cx - r + 2} y1={cy} x2={cx + r - 2} y2={cy} stroke={C.steel} strokeWidth="1.4" />
      <line x1={cx} y1={cy - r + 2} x2={cx} y2={cy + r - 2} stroke={C.steel} strokeWidth="1.4" />
      <circle cx={cx} cy={cy} r={r * 0.33} fill={C.steel} />
    </g>
  );
}

function Vehicle({ type, w, color }) {
  if (type === "moto") return (
    <svg viewBox="0 0 70 44" width={w}>
      <path d="M16 34 L34 22 L48 22 L54 34" fill="none" stroke={color} strokeWidth="4" strokeLinecap="round" />
      <rect x="30" y="18" width="16" height="5" rx="2" fill={color} />
      <path d="M46 22 L58 16" stroke={C.steel} strokeWidth="2" strokeLinecap="round" />
      <Wheel cx={16} cy={34} />
      <Wheel cx={54} cy={34} />
    </svg>
  );
  if (type === "truck") return (
    <svg viewBox="0 0 110 52" width={w}>
      <rect x="4" y="14" width="66" height="26" rx="3" fill={color} />
      <rect x="70" y="20" width="30" height="20" rx="3" fill="#4a6180" />
      <rect x="74" y="24" width="14" height="10" rx="1" fill="#bfe0ff" />
      <Wheel cx={24} cy={42} />
      <Wheel cx={50} cy={42} />
      <Wheel cx={88} cy={42} />
    </svg>
  );
  return (
    <svg viewBox="0 0 90 46" width={w}>
      <path d="M8 34 L14 22 Q16 18 22 18 L58 18 Q66 18 72 24 L82 30 Q84 31 84 34 L84 36 L8 36 Z" fill={color} />
      <path d="M22 20 L54 20 L60 27 L22 27 Z" fill="#bfe0ff" opacity="0.9" />
      <line x1="40" y1="20" x2="40" y2="27" stroke={color} strokeWidth="2" />
      <Wheel cx={24} cy={37} />
      <Wheel cx={68} cy={37} />
    </svg>
  );
}

function Garage({ mood, vehicles, time, sceneKey }) {
  const kinds = ["moto", "car", "truck", "car", "moto", "car", "moto"];
  const cols = ["#e05a3a", "#3b82f6", "#eab308", "#22c55e", "#a855f7", "#38bdf8", "#f97316"];
  const day = time === "day";
  const bg = day
    ? "linear-gradient(180deg,#7db6e8 0%,#a8cdea 34%, #2e3c4d 34.2%, #26313f 60%, #202b37 100%)"
    : "linear-gradient(180deg,#0b1526 0%,#101c30 34%, #1a2431 34.2%, #161f2a 60%, #121a23 100%)";
  return (
    <div style={{ position: "relative", height: 176, borderRadius: 16, overflow: "hidden",
      border: `1px solid ${C.border}`, background: bg, transition: "background 1s ease" }}>
      {/* céu: sol de dia, lua e estrelas à noite */}
      {day ? (
        <div style={{ position: "absolute", top: 8, right: 20, width: 30, height: 30, borderRadius: "50%",
          background: "radial-gradient(circle, #ffe9a8 0 55%, #ffd24d 60%, rgba(255,210,77,0) 75%)",
          boxShadow: "0 0 22px 8px rgba(255,214,90,.55)" }} />
      ) : (
        <>
          <div style={{ position: "absolute", top: 8, right: 24, width: 22, height: 22, borderRadius: "50%",
            background: "#e8edf4", boxShadow: "inset -6px -3px 0 0 #b9c4d4, 0 0 14px rgba(232,237,244,.5)" }} />
          {[[14,'8%'],[24,'26%'],[10,'44%'],[20,'60%'],[8,'71%']].map(([t,l],i) => (
            <div key={i} className="twinkle" style={{ position: "absolute", top: t, left: l, width: 3, height: 3,
              borderRadius: "50%", background: "#dfe7f2", animationDelay: (i*0.5)+"s" }} />
          ))}
        </>
      )}
      {/* fachada: faixa de teto */}
      <div style={{ position: "absolute", top: "34%", left: 0, right: 0, height: 8,
        background: "repeating-linear-gradient(45deg,#f2a51c 0 12px,#1c2430 12px 24px)", opacity: day ? 1 : 0.55 }} />
      {/* placa LubLub (fachada) */}
      <div style={{ position: "absolute", top: 10, left: 14, display: "flex", alignItems: "center", gap: 8 }}>
        <div style={{ background: "#ffffff", borderRadius: 8, padding: "5px 12px",
          boxShadow: "0 2px 8px rgba(0,0,0,.4)", opacity: day ? 1 : 0.82 }}>
          <img src={LOGO_IMG} alt="LubLub" style={{ height: 20, width: "auto", maxWidth: "none", display: "block" }} />
        </div>
        <span style={{ fontSize: 9.5, color: day ? "#dfe7f2" : C.muted, textShadow: "0 1px 2px rgba(0,0,0,.5)" }}>centro de distribuição</span>
      </div>
      {/* status: aberto/fechado */}
      <div style={{ position: "absolute", top: 12, right: 60, fontSize: 10, fontWeight: 800, letterSpacing: 1,
        color: day ? "#1d4620" : "#fff", background: day ? "#7fe08a" : "#c2453e", padding: "3px 9px", borderRadius: 99 }}>
        {day ? "ABERTO" : "FECHADO"}
      </div>
      {/* interior aberto (dia) ou porta de aço (noite) */}
      {day ? (
        <div style={{ position: "absolute", top: "39%", left: 0, right: 0, bottom: 24 }}>
          <div style={{ position: "absolute", right: 12, top: 4, display: "flex", gap: 4, opacity: 0.75 }}>
            {[0, 1, 2].map((i) => (
              <div key={i} style={{ width: 15, height: 24, borderRadius: 3, background: "#42525f",
                border: `1px solid ${C.border}`, boxShadow: "inset 0 4px 0 rgba(255,255,255,.08)" }} />
            ))}
          </div>
        </div>
      ) : (
        <div style={{ position: "absolute", top: "39%", left: "4%", right: "4%", bottom: 22, borderRadius: "6px 6px 0 0",
          background: "repeating-linear-gradient(180deg,#3a4757 0 9px,#2c3745 9px 12px)",
          border: `1px solid ${C.border}`, boxShadow: "inset 0 6px 12px rgba(0,0,0,.45)" }}>
          <div style={{ position: "absolute", top: "42%", left: "50%", transform: "translateX(-50%)",
            background: "#c2453e", color: "#fff", fontSize: 10, fontWeight: 800, letterSpacing: 1.5,
            padding: "3px 12px", borderRadius: 4, boxShadow: "0 2px 6px rgba(0,0,0,.4)" }}>FECHADO</div>
        </div>
      )}
      {/* piso */}
      <div style={{ position: "absolute", bottom: 0, left: 0, right: 0, height: 24,
        background: day ? "#3c4a59" : "#10161f", borderTop: `2px solid ${C.border}` }} />
      {/* cena viva */}
      <div key={sceneKey} style={{ position: "absolute", bottom: 4, left: 10, right: 8, display: "flex", alignItems: "flex-end", justifyContent: "space-between" }}>
        <div style={{ display: "flex", alignItems: "flex-end", gap: 6 }}>
          {day && Array.from({ length: vehicles }).map((_, i) => {
            const t = kinds[i % kinds.length];
            const w = t === "truck" ? 68 : t === "moto" ? 42 : 56;
            return (
              <div key={i} className="drive-in" style={{ animationDelay: 0.14 * i + "s" }}>
                <Vehicle type={t} w={w} color={cols[i % cols.length]} />
              </div>
            );
          })}
        </div>
        <div className={mood === "happy" ? "mech-cheer" : "mech-bob"}>
          <Worker w={58} mood={mood} />
        </div>
      </div>
    </div>
  );
}

const TIPS = [
  "Aumentar o preço pode melhorar OU piorar seu lucro — depende da elasticidade e da sua margem.",
  "Margem absoluta = margem unitária × volume. O jogo é maximizar o produto dos dois, não cada um sozinho.",
  "Se você sobe o preço e o volume quase não cai, estava cobrando barato demais.",
  "Commodity se ganha no volume; produto de marca se ganha na margem.",
  "Elasticidade aqui é relativa: olhe o gap vs concorrente, não só o seu preço.",
  "Subiu o preço e a margem total caiu? Você passou do pico da curva — volte um pouco.",
  "Sacrifique rodadas cedo testando preços diferentes: cada ponto no histórico revela a curva.",
  "Cliente fiel tolera prêmio; comprador de planilha compara centavo a centavo.",
  "Preço ótimo não é o maior preço nem o maior volume — é onde o retângulo (margem × volume) é maior.",
  "As elasticidades mudam a cada fase: o que era pra encarecer pode virar guerra de preço.",
];
const STATUS_MSGS = [
  "Abastecendo o estoque…", "Pesquisando preços dos concorrentes…", "Negociando com fornecedores…",
  "Conferindo os baldes de 20 L…", "Abrindo o centro de distribuição…", "Calibrando a tabela de preços…",
  "Ligando para as revendas…", "Separando os pedidos das frotas…",
];
const pickTips = (n) => [...TIPS].sort(() => Math.random() - 0.5).slice(0, n);

/* ---------------- Popup de preparação (dicas antes de começar) ---------------- */

function PrepPopup({ modeLabel, onDone }) {
  const [statusIdx, setStatusIdx] = useState(0);
  const [tipIdx, setTipIdx] = useState(0);
  const tips = useRef(pickTips(2)).current;
  useEffect(() => {
    const si = setInterval(() => setStatusIdx((i) => i + 1), 1200);
    const ti = setTimeout(() => setTipIdx(1), 3800);
    const done = setTimeout(onDone, 7600);
    return () => { clearInterval(si); clearTimeout(ti); clearTimeout(done); };
  }, []); // eslint-disable-line
  return (
    <div style={{ position: "fixed", inset: 0, zIndex: 120, background: "rgba(8,11,16,.8)",
      display: "flex", alignItems: "center", justifyContent: "center", padding: 16 }}>
      <div style={{ width: "100%", maxWidth: 400, background: C.panel, border: `1px solid ${C.border}`,
        borderRadius: 18, padding: 18, boxShadow: "0 24px 60px rgba(0,0,0,.55)", textAlign: "center" }}>
        <div style={{ fontSize: 11, letterSpacing: 2, color: C.muted, fontWeight: 700 }}>{modeLabel}</div>
        <div key={statusIdx} className="status-fade" style={{ fontSize: 15, fontWeight: 800, marginTop: 8, minHeight: 22 }}>
          {STATUS_MSGS[statusIdx % STATUS_MSGS.length]}
        </div>
        <div className="load-dots" style={{ margin: "10px 0 14px", display: "flex", gap: 5, justifyContent: "center" }}>
          {[0,1,2].map((i) => <span key={i} className="dot-pulse" style={{ width: 7, height: 7, borderRadius: "50%", background: C.oil, animationDelay: (i*0.2)+"s" }} />)}
        </div>
        <div style={{ background: C.panel2, border: `1px solid ${C.border}`, borderLeft: `4px solid ${C.oil}`,
          borderRadius: 12, padding: "12px 14px", textAlign: "left", minHeight: 74 }}>
          <div style={{ fontSize: 11, fontWeight: 800, color: C.oil, letterSpacing: 1 }}>💡 DICA</div>
          <div key={tipIdx} className="status-fade" style={{ fontSize: 13.5, marginTop: 4, lineHeight: 1.45 }}>
            {tips[tipIdx % tips.length]}
          </div>
        </div>
        <button onClick={onDone} style={{ marginTop: 14, padding: "8px 18px", fontSize: 13, fontWeight: 800,
          color: "#12250f", background: `linear-gradient(180deg,#5cf0a4,${C.green})`, border: "none",
          borderRadius: 99, cursor: "pointer" }}>começar agora ▸</button>
      </div>
    </div>
  );
}

/* ---------------- Popup de faturamento (porta abre → carrega → fecha) ---------------- */

function SellingPopup({ onDone }) {
  const [label, setLabel] = useState("Abrindo o galpão…");
  const tip = useRef(pickTips(1)[0]).current;
  useEffect(() => {
    const t1 = setTimeout(() => setLabel("Carregando os pedidos…"), 1100);
    const t2 = setTimeout(() => setLabel("Fechando o dia…"), 3600);
    const t3 = setTimeout(onDone, 4800);
    return () => { clearTimeout(t1); clearTimeout(t2); clearTimeout(t3); };
  }, []); // eslint-disable-line
  return (
    <div style={{ position: "fixed", inset: 0, zIndex: 120, background: "rgba(8,11,16,.78)",
      display: "flex", alignItems: "center", justifyContent: "center", padding: 16 }}>
      <div style={{ width: "100%", maxWidth: 430, background: C.panel, border: `1px solid ${C.border}`,
        borderRadius: 18, padding: 14, boxShadow: "0 24px 60px rgba(0,0,0,.55)" }}>
        {/* cena */}
        <div style={{ position: "relative", height: 200, borderRadius: 12, overflow: "hidden",
          border: `1px solid ${C.border}`,
          background: "linear-gradient(180deg,#7db6e8 0%,#a8cdea 40%, #2e3c4d 40.2%, #26313f 74%, #202b37 100%)" }}>
          {/* sol */}
          <div style={{ position: "absolute", top: 10, left: 18, width: 26, height: 26, borderRadius: "50%",
            background: "radial-gradient(circle,#ffe9a8 0 55%,#ffd24d 60%,rgba(255,210,77,0) 75%)",
            boxShadow: "0 0 20px 7px rgba(255,214,90,.5)" }} />
          {/* fachada */}
          <div style={{ position: "absolute", top: "40%", left: 0, right: 0, height: 8,
            background: "repeating-linear-gradient(45deg,#f2a51c 0 12px,#1c2430 12px 24px)" }} />
          <div style={{ position: "absolute", top: 12, right: 14, background: "#ffffff",
            padding: "4px 10px", borderRadius: 8, boxShadow: "0 2px 8px rgba(0,0,0,.4)" }}>
            <img src={LOGO_IMG} alt="LubLub" style={{ height: 17, width: "auto", maxWidth: "none", display: "block" }} />
          </div>
          {/* vão do galpão + interior (prateleiras) */}
          <div style={{ position: "absolute", top: "44%", left: "6%", right: "6%", bottom: 26,
            background: "#161f2a", border: `1px solid ${C.border}`, borderBottom: "none",
            borderRadius: "6px 6px 0 0", overflow: "hidden" }}>
            <div style={{ position: "absolute", inset: "10% 12%", display: "flex", gap: 8, justifyContent: "center", opacity: .8 }}>
              {[0,1,2,3].map((i) => (
                <div key={i} style={{ width: 14, height: "76%", background: "#42525f",
                  borderRadius: 3, boxShadow: "inset 0 4px 0 rgba(255,255,255,.08)" }} />
              ))}
            </div>
            {/* porta de aço animada: sobe no início, desce no fim */}
            <div className="dock-door" style={{ position: "absolute", inset: 0,
              background: "repeating-linear-gradient(180deg,#3a4757 0 9px,#2c3745 9px 12px)",
              boxShadow: "inset 0 6px 12px rgba(0,0,0,.45)" }} />
          </div>
          {/* caminhões entrando, carregando e nada mais bonito que rodas girando */}
          {[0, 1].map((i) => (
            <div key={i} className="truck-run" style={{ position: "absolute", bottom: 18,
              left: 0, animationDelay: (0.9 + i * 1.1) + "s", zIndex: 3 }}>
              <Vehicle type="truck" w={86} color={i ? "#eab308" : "#3d97f2"} />
            </div>
          ))}
          {/* caixas saindo do estoque e caindo na caçamba */}
          {[0, 1, 2, 3].map((i) => (
            <div key={i} className="crate-hop" style={{ position: "absolute", bottom: 58, left: "56%",
              width: 11, height: 11, borderRadius: 2, background: C.oil,
              border: "1px solid #b97f12", animationDelay: (1.9 + i * 0.38) + "s", zIndex: 4 }} />
          ))}
          {/* piso */}
          <div style={{ position: "absolute", bottom: 0, left: 0, right: 0, height: 22,
            background: "#3c4a59", borderTop: `2px solid ${C.border}` }} />
        </div>
        <div style={{ textAlign: "center", marginTop: 12 }}>
          <div style={{ fontSize: 15, fontWeight: 800 }}>{label}</div>
          <div className="load-dots" style={{ marginTop: 6, display: "flex", gap: 5, justifyContent: "center" }}>
            {[0,1,2].map((i) => <span key={i} style={{ width: 7, height: 7, borderRadius: "50%", background: C.oil, animationDelay: (i*0.2)+"s" }} className="dot-pulse" />)}
          </div>
          <div style={{ marginTop: 10, background: C.panel2, border: `1px solid ${C.border}`, borderLeft: `4px solid ${C.oil}`,
            borderRadius: 10, padding: "9px 12px", textAlign: "left" }}>
            <span style={{ fontSize: 10.5, fontWeight: 800, color: C.oil, letterSpacing: 1 }}>💡 DICA </span>
            <span style={{ fontSize: 12.5, lineHeight: 1.4 }}>{tip}</span>
          </div>
          <button onClick={onDone} style={{ marginTop: 10, padding: "6px 14px", fontSize: 12, fontWeight: 700,
            color: C.muted, background: "transparent", border: `1px solid ${C.border}`, borderRadius: 99, cursor: "pointer" }}>
            pular ▸
          </button>
        </div>
      </div>
    </div>
  );
}

/* ---------------- Telas / UI ---------------- */

function Intro({ onStart, phaseIdx }) {
  const demo = BASE_PRODUCTS;
  const ph = PHASES[phaseIdx % PHASES.length];
  return (
    <div style={{ paddingTop: 6 }}>
      <div style={{ background: "linear-gradient(180deg,#ffffff 0%,#eef2f6 78%,#dbe2ea 100%)",
        borderRadius: 16, padding: "16px 10px 10px", marginBottom: 10,
        boxShadow: "inset 0 -3px 0 #c7d0da, 0 4px 14px rgba(0,0,0,.35)",
        display: "flex", justifyContent: "center", alignItems: "flex-end", gap: 8 }}>
        {demo.map((p, i) => (
          <div key={p.id} className="float-soft" style={{ animationDelay: (i * 0.25) + "s" }}>
            <img src={PRODUCT_IMG[p.id]} alt={p.name}
              style={{ height: p.pack === "balde" ? 96 : 88, width: "auto", maxWidth: "none", objectFit: "contain",
                display: "block", filter: "drop-shadow(0 4px 5px rgba(0,0,0,.22))" }} />
          </div>
        ))}
      </div>
      <div style={{ textAlign: "center", fontSize: 12, letterSpacing: 3, color: C.oil, fontWeight: 700 }}>DISTRIBUIDORA DE LUBRIFICANTES</div>
      <div style={{ display: "flex", justifyContent: "center", margin: "8px 0 4px" }}>
        <div style={{ background: "#ffffff", borderRadius: 12, padding: "10px 22px",
          boxShadow: "0 4px 14px rgba(0,0,0,.35)" }}>
          <img src={LOGO_IMG} alt="LubLub" style={{ height: 42, width: "auto", maxWidth: "none", display: "block" }} />
        </div>
      </div>
      <p style={{ color: C.muted, fontSize: 16, textAlign: "center", marginTop: 2 }}>
        Você comanda a distribuidora LubLub. Precifique 5 lubrificantes para revendas, oficinas e frotas — e descubra, na prática, quanto cada cliente tolera.
      </p>

      <div style={{ marginTop: 14, background: C.panel2, border: `1px solid ${C.oil}`, borderRadius: 14, padding: "10px 14px", textAlign: "center" }}>
        <div style={{ fontSize: 12, letterSpacing: 1.5, color: C.oil, fontWeight: 800 }}>FASE {phaseIdx + 1} · {ph.title.toUpperCase()}</div>
        <div style={{ fontSize: 12.5, color: C.muted, marginTop: 3 }}>{ph.teaser}</div>
        <div style={{ fontSize: 11, color: C.faint, marginTop: 4 }}>As elasticidades mudam a cada fase — o óleo que aceitava preço alto pode virar guerra de preço, e vice-versa.</div>
      </div>

      <div style={{ background: C.panel, border: `1px solid ${C.border}`, borderRadius: 16, padding: 16, marginTop: 14 }}>
        <Rule n="1" title="A meta é margem absoluta" body="Ganha quem acumula mais lucro — não a maior margem por litro nem o maior volume. É o equilíbrio." />
        <Rule n="2" title="Consulte o histórico" body="Cada produto guarda seu preço, o do concorrente e o volume por rodada. Compare os pontos pra deduzir a elasticidade da fase." />
        <Rule n="3" title="Cada óleo reage diferente" body="Alguns clientes são fiéis (dá pra subir o preço); outros disputam no centavo (aí desconte pra vender). Descubra quem é quem nesta fase." />
      </div>
      <div style={{ fontSize: 12, letterSpacing: 2, color: C.muted, fontWeight: 700, textAlign: "center", marginTop: 20 }}>ESCOLHA COMO JOGAR</div>
      <ModeCard emoji="🔬" title="Modo laboratório" accent={C.blue} rounds="6 rodadas"
        body="Demanda estável, concorrente fixo, sem eventos. A curva de cada óleo se repete — ideal pra deduzir a elasticidade com calma."
        onClick={() => onStart("lab")} cta="Entrar no laboratório" />
      <ModeCard emoji="🏭" title="Modo mercado" accent={C.oil} rounds="8 rodadas"
        body="Alta do óleo base, guerra de preços, sazonalidade de frota. O desafio depois que você já domina as curvas."
        onClick={() => onStart("market")} cta="Abrir a distribuidora" />
      <p style={{ color: C.faint, fontSize: 12, textAlign: "center", marginTop: 12 }}>
        A demanda é determinística: o mesmo preço sempre vende o mesmo (no mercado, ajustado pelo evento visível).
      </p>
    </div>
  );
}
function Rule({ n, title, body }) {
  return (
    <div style={{ display: "flex", gap: 12, padding: "8px 0", alignItems: "flex-start" }}>
      <div style={{ minWidth: 30, height: 30, borderRadius: 9, background: C.panel2, color: C.oil, display: "grid", placeItems: "center", fontWeight: 800, border: `1px solid ${C.border}` }}>{n}</div>
      <div><div style={{ fontWeight: 700 }}>{title}</div><div style={{ color: C.muted, fontSize: 14 }}>{body}</div></div>
    </div>
  );
}
function ModeCard({ emoji, title, body, rounds, accent, onClick, cta }) {
  return (
    <button onClick={onClick} className="mode-card" style={{ width: "100%", textAlign: "left", marginTop: 12, cursor: "pointer",
      background: C.panel, border: `1px solid ${C.border}`, borderLeft: `4px solid ${accent}`, borderRadius: 14, padding: 14, color: C.text }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
        <div style={{ fontWeight: 800, fontSize: 17 }}>{emoji} {title}</div>
        <div style={{ fontSize: 11, color: accent, fontWeight: 700, whiteSpace: "nowrap" }}>{rounds}</div>
      </div>
      <div style={{ fontSize: 13, color: C.muted, marginTop: 6 }}>{body}</div>
      <div style={{ fontSize: 13, fontWeight: 800, color: accent, marginTop: 10 }}>{cta} →</div>
    </button>
  );
}

function TopBar({ round, cash, par, total, mode }) {
  const pct = par > 0 ? Math.min(100, (cash / par) * 100) : 0;
  return (
    <div style={{ background: C.panel, border: `1px solid ${C.border}`, borderRadius: 16, padding: "14px 16px", marginTop: 12 }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-end" }}>
        <div>
          <div style={{ fontSize: 12, color: C.muted, letterSpacing: 1 }}>CAIXA ACUMULADO
            <span style={{ marginLeft: 8, color: mode === "lab" ? C.blue : C.oil, fontWeight: 700 }}>{mode === "lab" ? "· 🔬 laboratório" : "· 🏭 mercado"}</span>
          </div>
          <div style={{ fontSize: 30, fontWeight: 800, color: C.green, lineHeight: 1 }}>{money(cash)}</div>
        </div>
        <div style={{ textAlign: "right" }}>
          <div style={{ fontSize: 12, color: C.muted }}>RODADA</div>
          <div style={{ fontSize: 22, fontWeight: 800 }}>{round}<span style={{ color: C.faint, fontSize: 15 }}>/{total}</span></div>
        </div>
      </div>
      <div style={{ marginTop: 10, height: 6, background: C.panel2, borderRadius: 99, overflow: "hidden" }}>
        <div style={{ height: "100%", width: pct + "%", background: `linear-gradient(90deg,${C.greenDim},${C.green})`, transition: "width .8s ease" }} />
      </div>
      <div style={{ fontSize: 11, color: C.faint, marginTop: 4 }}>vs. jogo perfeito acumulado</div>
    </div>
  );
}

function EventBanner({ msg, shock }) {
  const up = shock > 1.01, down = shock < 0.99, col = up ? C.green : down ? C.red : C.blue;
  return (
    <div style={{ marginTop: 12, background: C.panel2, border: `1px solid ${C.border}`, borderLeft: `4px solid ${col}`, borderRadius: 12, padding: "10px 14px", display: "flex", justifyContent: "space-between", alignItems: "center", gap: 8 }}>
      <span style={{ fontSize: 14 }}>{msg}</span>
      <span style={{ fontSize: 12, fontWeight: 800, color: col, whiteSpace: "nowrap" }}>{up ? "▲" : down ? "▼" : "="} ×{shock.toFixed(2)}</span>
    </div>
  );
}

function PriceInput({ value, min, max, step, onCommit }) {
  const [txt, setTxt] = useState(String(value));
  const [focus, setFocus] = useState(false);
  useEffect(() => { if (!focus) setTxt(String(value)); }, [value, focus]);
  const handle = (s) => { setTxt(s); const n = parseFloat(s.replace(",", ".")); if (!isNaN(n)) onCommit(Math.min(max, Math.max(0, n))); };
  const blur = () => {
    setFocus(false); let n = parseFloat(txt.replace(",", ".")); if (isNaN(n)) n = value;
    n = Math.round(Math.min(max, Math.max(min, n)) / step) * step; onCommit(n); setTxt(String(n));
  };
  return (
    <input type="text" inputMode="decimal" value={txt}
      onChange={(e) => handle(e.target.value)} onFocus={(e) => { setFocus(true); e.target.select(); }} onBlur={blur}
      style={{ width: 78, textAlign: "right", fontSize: 20, fontWeight: 800, color: C.oil, background: C.panel2,
        border: `1px solid ${C.border}`, borderRadius: 8, padding: "2px 6px", outline: "none" }} />
  );
}

function ProductCard({ p, phase, res, onPrice, open, xMode, toggle, setX }) {
  const unit = p.price - p.cost, vsComp = p.price - p.competitor;
  const step = p.pack === "balde" ? 1 : 0.5;
  const rows = p.history.map((h) => ({ round: h.round, price: h.price, comp: h.competitor, gap: +(h.price - h.competitor).toFixed(2), vol: h.vol, margin: h.margin }));
  return (
    <div style={{ background: C.panel, border: `1px solid ${C.border}`, borderRadius: 16, padding: 14 }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", gap: 8 }}>
        <div style={{ display: "flex", gap: 10, alignItems: "center", minWidth: 0, flex: 1 }}>
          <BottleTile p={p} w={54} />
          <div style={{ minWidth: 0 }}>
            <div style={{ fontWeight: 800, fontSize: 15, lineHeight: 1.1 }}>{p.name}</div>
            <div style={{ fontSize: 10.5, color: C.faint, letterSpacing: 0.4 }}>{p.tag}</div>
            <div style={{ fontSize: 12, color: C.muted, marginTop: 2 }}>Custo {money2(p.cost)} · Concorrente <b style={{ color: C.text }}>{money2(p.competitor)}</b></div>
          </div>
        </div>
        <div style={{ textAlign: "right", flexShrink: 0 }}>
          {phase === "pricing" ? (
            <div style={{ display: "flex", alignItems: "center", justifyContent: "flex-end", gap: 4 }}>
              <span style={{ fontSize: 14, fontWeight: 800, color: C.oil }}>R$</span>
              <PriceInput value={p.price} min={p.cost} max={p.max} step={step} onCommit={onPrice} />
            </div>
          ) : (
            <div style={{ fontSize: 21, fontWeight: 800, color: C.oil }}>{money2(p.price)}</div>
          )}
          <div style={{ fontSize: 10, color: C.faint }}>por {p.unit}</div>
          <div style={{ fontSize: 11, color: vsComp === 0 ? C.muted : vsComp > 0 ? C.red : C.green }}>
            {vsComp === 0 ? "= concorrente" : `${vsComp > 0 ? "+" : ""}${money2(vsComp)} vs conc.`}
          </div>
        </div>
      </div>
      <input type="range" min={p.cost} max={p.max} step={step} value={p.price} disabled={phase !== "pricing"}
        onChange={(e) => onPrice(parseFloat(e.target.value))} className="pr-slider"
        style={{ width: "100%", marginTop: 12, opacity: phase === "pricing" ? 1 : 0.55 }} />
      <div style={{ display: "flex", justifyContent: "space-between", fontSize: 11, color: C.faint }}>
        <span>margem unitária <b style={{ color: unit >= 0 ? C.green : C.red }}>{money2(unit)}</b></span>
        <span>{money2(p.cost)} — {money2(p.max)}</span>
      </div>

      {phase === "result" && res && (
        <div style={{ marginTop: 12, display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 8 }}>
          <Stat label="Volume" value={res.vol} sub={res.prev ? deltaTxt(res.vol - res.prev.vol, "un") : null} />
          <Stat label="Margem unit." value={money2(res.unit)} />
          <Stat label="Margem total" value={money(res.margin)} big sub={res.prev ? deltaTxt(res.margin - res.prev.margin, "R$", true) : null} />
        </div>
      )}

      {p.history.length > 0 && (
        <button onClick={toggle} style={ghostBtn}>
          {open ? "▲ fechar análise" : `📊 analisar histórico (${p.history.length} ${p.history.length === 1 ? "rodada" : "rodadas"})`}
        </button>
      )}
      {open && (
        <div style={{ marginTop: 8 }}>
          <div style={{ height: 194 }}>
            <ResponsiveContainer>
              <ComposedChart data={rows} margin={{ top: 18, right: 4, bottom: 2, left: -12 }}>
                <CartesianGrid stroke={C.border} strokeDasharray="3 3" vertical={false} />
                <XAxis dataKey="round" tick={false} axisLine={{ stroke: C.border }} height={4} />
                <YAxis yAxisId="m" tick={{ fill: C.oil, fontSize: 10 }} width={42}
                  tickFormatter={(v) => (v >= 1000 ? "R$" + (v / 1000).toFixed(1) + "k" : "R$" + v)} />
                <YAxis yAxisId="v" orientation="right" tick={{ fill: C.blue, fontSize: 10 }} width={38}
                  tickFormatter={(v) => "R$" + Math.round(v)} />
                <YAxis yAxisId="q" hide domain={[0, (max) => max * 1.25]} />
                <Tooltip contentStyle={{ background: C.panel2, border: `1px solid ${C.border}`, borderRadius: 8, color: C.text }}
                  formatter={(v, n) => (n === "preço" ? [money2(v), "seu preço"] : n === "volume" ? [v + " un", "volume"] : [money(v), "margem total"])}
                  labelFormatter={(l) => "Rodada " + l} />
                <Legend wrapperStyle={{ fontSize: 11 }} />
                <Bar yAxisId="m" dataKey="margin" name="margem" fill={C.oil} fillOpacity={0.85} barSize={24} radius={[3, 3, 0, 0]}>
                  <LabelList dataKey="round" position="top" formatter={(v) => "R" + v} fill={C.muted} fontSize={10} fontWeight={700} />
                </Bar>
                <Line yAxisId="q" type="monotone" dataKey="vol" name="volume" stroke={C.green} strokeWidth={2}
                  strokeDasharray="5 4" dot={{ r: 2.5, fill: C.green }} />
                <Line yAxisId="v" type="monotone" dataKey="price" name="preço" stroke={C.blue} strokeWidth={2} dot={{ r: 3, fill: C.blue }} />
              </ComposedChart>
            </ResponsiveContainer>
          </div>
          <div style={{ fontSize: 11, color: C.faint, textAlign: "center", marginTop: -2 }}>
            barras âmbar = margem (seu objetivo) · linha azul = preço · tracejada verde = volume · R1, R2… = rodada
          </div>

          <div style={{ overflowX: "auto", marginTop: 6 }}>
            <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 12 }}>
              <thead><tr style={{ color: C.muted }}>
                <th style={thL}>Rod.</th><th style={th}>Preço</th><th style={th}>Conc.</th><th style={th}>Δ</th><th style={th}>Vol.</th><th style={th}>Margem</th>
              </tr></thead>
              <tbody>
                {rows.map((r, i) => {
                  const prev = rows[i - 1], volDown = prev && r.price > prev.price;
                  return (
                    <tr key={r.round} style={{ borderTop: `1px solid ${C.border}` }}>
                      <td style={tdL}>{r.round}</td>
                      <td style={td}>{money2(r.price)}</td>
                      <td style={{ ...td, color: C.muted }}>{money2(r.comp)}</td>
                      <td style={{ ...td, color: r.gap === 0 ? C.faint : r.gap > 0 ? C.red : C.green }}>{r.gap > 0 ? "+" : ""}{r.gap}</td>
                      <td style={{ ...td, color: volDown ? C.red : C.text }}>{r.vol}</td>
                      <td style={{ ...td, fontWeight: 700, color: C.green }}>{money(r.margin)}</td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
          <div style={{ fontSize: 11, color: C.faint, marginTop: 6 }}>
            💡 Compare duas rodadas: preço subiu pouco e volume desabou = <b>elástico</b>. Volume quase não mexeu = <b>inelástico</b>.
          </div>
        </div>
      )}
    </div>
  );
}

function MarginHistory({ log }) {
  const data = log.map((r) => ({ ...r, eff: r.par > 0 ? r.margin / r.par : 0 }));
  const colorFor = (e) => (e >= 0.8 ? C.green : e >= 0.6 ? C.oil : C.red);
  return (
    <div style={{ marginTop: 14, background: C.panel, border: `1px solid ${C.border}`, borderRadius: 16, padding: 14 }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "baseline" }}>
        <div style={{ fontWeight: 800, fontSize: 15 }}>Margem capturada por rodada</div>
        <div style={{ fontSize: 11, color: C.faint }}>verde ótima · âmbar ok · vermelho fraca</div>
      </div>
      <div style={{ height: 176, marginTop: 8 }}>
        <ResponsiveContainer>
          <BarChart data={data} margin={{ top: 8, right: 6, bottom: 2, left: -6 }}>
            <CartesianGrid stroke={C.border} strokeDasharray="3 3" vertical={false} />
            <XAxis dataKey="round" tick={{ fill: C.muted, fontSize: 11 }} tickFormatter={(v) => "R" + v} />
            <YAxis tick={{ fill: C.muted, fontSize: 10 }} width={40} tickFormatter={(v) => (v >= 1000 ? "R$" + (v / 1000).toFixed(0) + "k" : "R$" + v)} />
            <Tooltip contentStyle={{ background: C.panel2, border: `1px solid ${C.border}`, borderRadius: 8, color: C.text }}
              formatter={(v, n, o) => [money(v) + `  (${Math.round(o.payload.eff * 100)}% do potencial)`, "margem"]}
              labelFormatter={(l) => "Rodada " + l} cursor={{ fill: "rgba(255,255,255,.04)" }} />
            <Bar dataKey="margin" name="margem" radius={[4, 4, 0, 0]}>
              {data.map((d, i) => <Cell key={i} fill={colorFor(d.eff)} />)}
              <LabelList dataKey="eff" position="insideTop" formatter={(v) => Math.round(v * 100) + "%"}
                fill="#10251a" fontSize={11} fontWeight={800} />
            </Bar>
          </BarChart>
        </ResponsiveContainer>
      </div>
    </div>
  );
}

function MiniTab({ active, onClick, children }) {
  return (
    <button onClick={onClick} style={{ flex: 1, padding: "6px 4px", fontSize: 11, fontWeight: 700, borderRadius: 8, cursor: "pointer",
      border: `1px solid ${active ? C.blue : C.border}`, background: active ? C.panel2 : "transparent", color: active ? C.text : C.muted }}>{children}</button>
  );
}
const th = { padding: "4px 6px", fontWeight: 700, textAlign: "right" };
const thL = { ...th, textAlign: "left" };
const td = { padding: "4px 6px", textAlign: "right", whiteSpace: "nowrap" };
const tdL = { ...td, textAlign: "left", color: C.muted };

function Stat({ label, value, sub, big }) {
  return (
    <div style={{ background: C.panel2, borderRadius: 10, padding: "8px 10px", textAlign: "center" }}>
      <div style={{ fontSize: 10, color: C.muted, letterSpacing: 0.5 }}>{label}</div>
      <div style={{ fontSize: big ? 17 : 15, fontWeight: 800, color: big ? C.green : C.text }}>{value}</div>
      {sub && <div style={{ fontSize: 10, marginTop: 1 }}>{sub}</div>}
    </div>
  );
}
function deltaTxt(d, unit, currency) {
  if (Math.round(d) === 0) return <span style={{ color: C.faint }}>igual à rodada anterior</span>;
  const pos = d > 0, val = currency ? money(Math.abs(d)) : Math.abs(Math.round(d)) + " " + unit;
  return <span style={{ color: pos ? C.green : C.red, fontWeight: 700 }}>{pos ? "▲ +" : "▼ -"}{val}</span>;
}

function RoundSummary({ lr, onNext, last }) {
  const eff = lr.roundPar > 0 ? lr.roundMargin / lr.roundPar : 0;
  const grade = eff >= 0.92 ? ["Rodada impecável!", C.green] : eff >= 0.75 ? ["Boa rodada.", C.green] : eff >= 0.55 ? ["Deu pra faturar.", C.oil] : ["Dava pra faturar bem mais.", C.red];
  return (
    <div style={{ marginTop: 16, background: C.panel, border: `1px solid ${C.border}`, borderRadius: 16, padding: 16, textAlign: "center" }}>
      <div style={{ color: C.muted, fontSize: 13 }}>Margem da rodada</div>
      <div style={{ fontSize: 34, fontWeight: 800, color: C.green }}>{money(lr.roundMargin)}</div>
      <div style={{ fontSize: 13, color: grade[1], fontWeight: 700, marginTop: 2 }}>{grade[0]}</div>
      <div style={{ fontSize: 12, color: C.faint, marginTop: 2 }}>potencial da rodada: {money(lr.roundPar)} · você pegou {Math.round(eff * 100)}%</div>
      <BigButton onClick={onNext} label={last ? "VER RESULTADO FINAL" : "PRÓXIMA RODADA →"} />
    </div>
  );
}

function GameOverModal({ total, par, ratio, best, items, mode, earlyWin, totalRounds, onSeeResults, onRestart }) {
  const eff = best ? Math.round(best.eff * 100) : 0;
  return (
    <div onClick={onSeeResults} style={{ position: "fixed", inset: 0, zIndex: 100, background: "rgba(8,11,16,.74)", display: "flex", alignItems: "center", justifyContent: "center", padding: 16 }}>
      <div onClick={(e) => e.stopPropagation()} style={{ width: "100%", maxWidth: 420, background: C.panel, border: `1px solid ${C.border}`, borderRadius: 18, padding: 18, boxShadow: "0 24px 60px rgba(0,0,0,.55)" }}>
        <div style={{ textAlign: "center" }}>
          <div style={{ fontSize: 12, letterSpacing: 2, color: earlyWin ? C.green : C.oil, fontWeight: 800 }}>{earlyWin ? "🎯 VITÓRIA ANTECIPADA" : "🏁 FIM DE JOGO"}</div>
          <div style={{ fontSize: 12, color: C.muted, marginTop: 10 }}>Margem total nas {totalRounds} rodadas</div>
          <div style={{ fontSize: 42, fontWeight: 800, color: C.green, lineHeight: 1.05 }}>{money(total)}</div>
          <div style={{ fontSize: 12, color: C.faint, marginTop: 2 }}>{Math.round(ratio * 100)}% do jogo perfeito ({money(par)})</div>
        </div>

        {best && (
          <div style={{ marginTop: 14, background: C.panel2, border: `1px solid ${C.oil}`, borderRadius: 14, padding: "12px 14px" }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
              <span style={{ fontSize: 12, fontWeight: 800, color: C.oil, letterSpacing: 0.5 }}>⭐ MELHOR RODADA</span>
              <span style={{ fontSize: 12, fontWeight: 700, color: C.oil }}>{eff}% do potencial</span>
            </div>
            <div style={{ fontSize: 22, fontWeight: 800, marginTop: 3 }}>Rodada {best.round} · <span style={{ color: C.green }}>{money(best.margin)}</span></div>
            <button onClick={() => downloadBestRoundPDF({ round: best.round, margin: best.margin, par: best.par, mode, items })}
              style={{ width: "100%", marginTop: 10, padding: 9, fontSize: 12.5, fontWeight: 800, color: C.oil, background: "transparent", border: `1px solid ${C.oil}`, borderRadius: 10, cursor: "pointer" }}>
              📄 Baixar melhor rodada (PDF)
            </button>
          </div>
        )}

        <div style={{ textAlign: "center", fontSize: 13, color: C.muted, marginTop: 16, fontWeight: 700 }}>O que você quer fazer agora?</div>
        <button onClick={onRestart} className="pr-cta" style={{ width: "100%", marginTop: 10, padding: 14, fontSize: 15, fontWeight: 800, color: "#12250f",
          background: `linear-gradient(180deg,#5cf0a4,${C.green})`, border: "none", borderRadius: 12, cursor: "pointer" }}>
          🔁 Jogar outra vez
        </button>
        <button onClick={onSeeResults} style={{ width: "100%", marginTop: 8, padding: 12, fontSize: 14, fontWeight: 800, color: C.text, background: C.panel2, border: `1px solid ${C.border}`, borderRadius: 12, cursor: "pointer" }}>
          📊 Ver resultados e o porquê
        </button>
      </div>
    </div>
  );
}

function EndScreen({ total, par, ratio, products, log, mode, phaseIdx, earlyWin, finishedRound, totalRounds, onRestart }) {
  const rank = [[0.92, "🏆 Mestre da Precificação", C.oil], [0.8, "💎 Gerente Sênior", C.green], [0.65, "📈 Analista Promissor", C.blue], [0.45, "🌱 Balconista", C.steel], [0, "😅 Ainda dá pra melhorar", C.red]].find(([t]) => ratio >= t);
  const ph = PHASES[phaseIdx % PHASES.length];
  const byE = [...products].sort((a, b) => elasticityAt(b.competitor, b) - elasticityAt(a.competitor, a));
  const elasLabel = (p) => { const i = byE.findIndex((x) => x.id === p.id); return i === 0 ? ["+ SENSÍVEL A PREÇO", C.red] : i === byE.length - 1 ? ["+ FIEL (inelástico)", C.green] : ["INTERMEDIÁRIO", C.oil]; };
  const best = (log || []).map((r) => ({ ...r, eff: r.par > 0 ? r.margin / r.par : 0 })).sort((a, b) => b.eff - a.eff)[0];
  const bestItems = best ? products.map((p) => { const h = p.history.find((x) => x.round === best.round) || {}; return { name: p.name, price: h.price || 0, vol: h.vol || 0, margin: h.margin || 0 }; }) : [];
  const [showModal, setShowModal] = useState(true);

  return (
    <div style={{ paddingTop: 12 }}>
      {showModal && <GameOverModal total={total} par={par} ratio={ratio} best={best} items={bestItems} mode={mode} earlyWin={earlyWin} totalRounds={totalRounds} onSeeResults={() => setShowModal(false)} onRestart={onRestart} />}
      <div style={{ textAlign: "center" }}>
        <div className={ratio >= 0.65 ? "mech-cheer" : "mech-bob"} style={{ display: "inline-block" }}><Worker w={84} mood={ratio >= 0.65 ? "happy" : "sad"} /></div>
        <div style={{ fontSize: 13, letterSpacing: 3, color: C.oil, fontWeight: 700, marginTop: 4 }}>{earlyWin ? "VITÓRIA ANTECIPADA" : "FIM DE JOGO"}</div>
        <div style={{ fontSize: 44 }}>{money(total)}</div>
        <div style={{ color: C.muted, fontSize: 13 }}>margem total nas {totalRounds} rodadas</div>
        <div style={{ marginTop: 10, display: "inline-block", background: C.panel, border: `1px solid ${C.border}`, borderRadius: 99, padding: "8px 18px", color: rank[2], fontWeight: 800, fontSize: 18 }}>{rank[1]}</div>
        <div style={{ color: C.faint, fontSize: 12, marginTop: 8 }}>{Math.round(ratio * 100)}% do jogo perfeito ({money(par)})</div>
      </div>

      {earlyWin && (
        <div style={{ marginTop: 14, background: C.panel, border: `1px solid ${C.green}`, borderRadius: 14, padding: "12px 14px", textAlign: "center" }}>
          <div style={{ fontWeight: 800, color: C.green }}>🎯 Precificação perfeita!</div>
          <div style={{ fontSize: 13, color: C.muted, marginTop: 2 }}>
            Você acertou 100% do potencial na rodada {finishedRound} — todos os 5 óleos no preço ótimo — e fechou o jogo antes das {totalRounds} rodadas.
          </div>
        </div>
      )}

      {best && (
        <button onClick={() => setShowModal(true)} className="mode-card" style={{ width: "100%", marginTop: 12, cursor: "pointer",
          background: C.panel, border: `1px solid ${C.oil}`, borderRadius: 14, padding: "12px 14px", color: C.text, display: "flex", alignItems: "center", justifyContent: "space-between", gap: 10 }}>
          <div style={{ textAlign: "left" }}>
            <div style={{ fontSize: 11, color: C.oil, letterSpacing: 0.5, fontWeight: 800 }}>⭐ MELHOR RODADA</div>
            <div style={{ fontSize: 20, fontWeight: 800 }}>Rodada {best.round} · {money(best.margin)}</div>
          </div>
          <div style={{ fontSize: 12, color: C.oil, fontWeight: 800, whiteSpace: "nowrap" }}>abrir resumo / PDF</div>
        </button>
      )}

      <h3 style={{ marginTop: 22, marginBottom: 2 }}>Os preços ideais desta fase — e o porquê</h3>
      <p style={{ color: C.muted, fontSize: 13, marginTop: 0 }}>
        <b style={{ color: C.oil }}>Fase {phaseIdx + 1} · {ph.title}.</b> {ph.scenario}
      </p>
      <div style={{ display: "grid", gap: 10 }}>
        {products.map((p) => {
          const opt = optimalOf(p);
          const diff = Math.round((opt.price / p.competitor - 1) * 100);
          const dcol = diff > 0 ? C.oil : diff < 0 ? C.green : C.muted;
          const [lbl, lcol] = elasLabel(p);
          return (
            <div key={p.id} style={{ background: C.panel, border: `1px solid ${C.border}`, borderRadius: 14, padding: 12, display: "flex", gap: 12 }}>
              <BottleTile p={p} w={48} />
              <div style={{ flex: 1 }}>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", gap: 6 }}>
                  <div style={{ fontWeight: 800, fontSize: 14 }}>{p.name}</div>
                  <div style={{ fontSize: 10.5, color: lcol, fontWeight: 700, whiteSpace: "nowrap" }}>{lbl}</div>
                </div>
                <div style={{ display: "flex", alignItems: "baseline", gap: 8, marginTop: 4, flexWrap: "wrap" }}>
                  <span style={{ fontSize: 11, color: C.muted }}>Preço ideal</span>
                  <span style={{ fontSize: 19, fontWeight: 800, color: C.oil }}>{money2(opt.price)}</span>
                  <span style={{ fontSize: 11, color: C.faint }}>/ {p.unit}</span>
                  <span style={{ fontSize: 11, fontWeight: 700, color: dcol }}>{diff > 0 ? "+" : ""}{diff}% vs concorrente ({money2(p.competitor)})</span>
                </div>
                <div style={{ fontSize: 12.5, color: C.muted, marginTop: 5 }}>{p.nature}</div>
                <div style={{ fontSize: 12.5, marginTop: 5 }}>💡 {lessonFor(p)}</div>
              </div>
            </div>
          );
        })}
      </div>
      <BigButton onClick={onRestart} label="JOGAR DE NOVO" />
    </div>
  );
}

function BigButton({ onClick, label, hint }) {
  return (
    <div style={{ marginTop: 18 }}>
      <button onClick={onClick} className="pr-cta" style={{ width: "100%", padding: 16, fontSize: 17, fontWeight: 800, letterSpacing: 0.5,
        color: "#12250f", background: `linear-gradient(180deg,#5cf0a4,${C.green})`, border: "none", borderRadius: 14, cursor: "pointer", boxShadow: "0 8px 24px rgba(57,217,138,.25)" }}>{label}</button>
      {hint && <div style={{ textAlign: "center", fontSize: 12, color: C.faint, marginTop: 6 }}>{hint}</div>}
    </div>
  );
}
const ghostBtn = { marginTop: 10, width: "100%", padding: 8, fontSize: 12, fontWeight: 700, color: C.blue, background: "transparent", border: `1px dashed ${C.border}`, borderRadius: 10, cursor: "pointer" };

function StyleTag() {
  const css = `
    @keyframes riseUp{0%{transform:translateY(0) scale(.6);opacity:0}15%{opacity:1}100%{transform:translateY(-72vh) scale(1.1) rotate(20deg);opacity:0}}
    @keyframes blink{0%,92%,100%{transform:scaleY(1)}96%{transform:scaleY(.1)}}
    @keyframes bob{0%,100%{transform:translateY(0)}50%{transform:translateY(-3px)}}
    @keyframes cheer{0%,100%{transform:translateY(0) rotate(0)}20%{transform:translateY(-9px) rotate(-3deg)}45%{transform:translateY(0)}65%{transform:translateY(-5px) rotate(3deg)}85%{transform:translateY(0)}}
    @keyframes driveIn{0%{transform:translateX(-130px);opacity:0}100%{transform:translateX(0);opacity:1}}
    @keyframes spin{to{transform:rotate(360deg)}}
    @keyframes floaty{0%,100%{transform:translateY(0)}50%{transform:translateY(-5px)}}
    @keyframes twinkle{0%,100%{opacity:.25}50%{opacity:1}}
    .twinkle{animation:twinkle 2.4s ease-in-out infinite}
    @keyframes doorLift{0%{transform:translateY(0)}100%{transform:translateY(-96%)}}
    @keyframes doorDrop{0%{transform:translateY(-96%)}100%{transform:translateY(0)}}
    .dock-door{animation:doorLift .8s ease-in-out .25s forwards, doorDrop .8s ease-in-out 3.7s forwards}
    @keyframes truckRun{0%{transform:translateX(-140px)}28%{transform:translateX(120px)}72%{transform:translateX(122px)}100%{transform:translateX(520px)}}
    .truck-run{animation:truckRun 3.4s ease-in-out forwards}
    .truck-run .wheel{animation:spin 1.1s linear infinite}
    @keyframes crateHop{0%{opacity:0;transform:translate(0,0) scale(.7)}12%{opacity:1}
      55%{transform:translate(-52px,-32px) scale(1)}82%{opacity:1;transform:translate(-96px,-2px) scale(.95)}
      100%{opacity:0;transform:translate(-96px,6px) scale(.9)}}
    .crate-hop{opacity:0;animation:crateHop 1s cubic-bezier(.3,.7,.4,1) forwards}
    @keyframes dotPulse{0%,100%{opacity:.25;transform:scale(.8)}50%{opacity:1;transform:scale(1.15)}}
    .dot-pulse{animation:dotPulse 1s ease-in-out infinite}
    @keyframes statusFade{0%{opacity:0;transform:translateY(4px)}100%{opacity:1;transform:translateY(0)}}
    .status-fade{animation:statusFade .45s ease-out}
    .eye{transform-box:fill-box;transform-origin:center;animation:blink 4.2s infinite}
    .mech-bob{animation:bob 2.6s ease-in-out infinite}
    .mech-cheer{animation:cheer 1.1s ease-in-out infinite}
    .drive-in{animation:driveIn .55s ease-out both}
    .drive-in .wheel{animation:spin 1.1s linear infinite}
    .float-soft{animation:floaty 3s ease-in-out infinite}
    .pr-cta{transition:transform .08s ease,box-shadow .2s ease}
    .pr-cta:hover{transform:translateY(-1px)} .pr-cta:active{transform:translateY(1px) scale(.99)}
    .mode-card{transition:transform .1s ease} .mode-card:hover{transform:translateY(-2px)} .mode-card:active{transform:translateY(0)}
    .pr-slider{-webkit-appearance:none;appearance:none;height:8px;border-radius:99px;background:${C.panel2};outline:none;cursor:pointer}
    .pr-slider::-webkit-slider-thumb{-webkit-appearance:none;width:22px;height:22px;border-radius:50%;background:${C.oil};border:3px solid ${C.bg};box-shadow:0 2px 8px rgba(0,0,0,.5);cursor:pointer}
    .pr-slider::-moz-range-thumb{width:20px;height:20px;border-radius:50%;background:${C.oil};border:3px solid ${C.bg};cursor:pointer}
    @media (prefers-reduced-motion:reduce){*{animation:none!important;transition:none!important}}
    *{scrollbar-width:thin;scrollbar-color:${C.border} transparent}
    ::-webkit-scrollbar{width:10px;height:10px}
    ::-webkit-scrollbar-track{background:transparent}
    ::-webkit-scrollbar-thumb{background:${C.border};border-radius:8px;border:2px solid ${C.bg};background-clip:padding-box}
    ::-webkit-scrollbar-thumb:hover{background:#4c5b6d}
    ::-webkit-scrollbar-corner{background:transparent}
  `;
  return <style dangerouslySetInnerHTML={{ __html: css }} />;
}
